function App() {
  const { isAuthenticated, loading } = useAuth();
  const isCallback = window.location.pathname === '/callback';

  if (loading) {
    return (
      <div style={{ 
        display: 'flex', 
        justifyContent: 'center', 
        alignItems: 'center', 
        height: '100vh',
        fontFamily: 'Arial, sans-serif'
      }}>
        <h2>Loading...</h2>
      </div>
    );
  }

  if (isCallback) {
    return <CallbackPage />;
  }

  return isAuthenticated ? <ProfilePage /> : <LoginPage />;
}

function Root() {
  return (
    <AuthProvider>
      <App />
    </AuthProvider>
  );
}

